import heapq
class Solution:
    def minimumPairRemoval(self, nums):
        n = len(nums)
        if n <= 1:
            return 0
        val = list(nums)
        prev = [i - 1 for i in range(n)]
        nxt = [i + 1 for i in range(n)]
        alive = [True] * n
        bad = 0
        for i in range(n - 1):
            if val[i] > val[i + 1]:
                bad += 1
        heap = []
        for i in range(n - 1):
            heapq.heappush(heap, (val[i] + val[i + 1], i, i + 1))
        ops = 0
        while bad > 0:
            while True:
                s, i, j = heapq.heappop(heap)
                if alive[i] and alive[j] and nxt[i] == j and val[i] + val[j] == s:
                    break
            p = prev[i]
            q = nxt[j]
            vi_old, vj_old = val[i], val[j]
            if vi_old > vj_old:
                bad -= 1
            if p != -1 and val[p] > vi_old:
                bad -= 1
            if q < n and vj_old > val[q]:
                bad -= 1
            newv = vi_old + vj_old
            val[i] = newv
            alive[j] = False
            nxt[i] = q
            if q < n:
                prev[q] = i
            if p != -1:
                if val[p] > newv:
                    bad += 1
                heapq.heappush(heap, (val[p] + newv, p, i))
            if q < n:
                if newv > val[q]:
                    bad += 1
                heapq.heappush(heap, (newv + val[q], i, q))
            ops += 1
        return ops

