var minimumPairRemoval = function(nums) {
    let a = nums.slice();
    let ops = 0;
    while (true) {
        const n = a.length;
        let sortedOk = true;
        for (let i = 0; i < n - 1; i++) {
            if (a[i] > a[i + 1]) { sortedOk = false; break; }
        }
        if (sortedOk) return ops;
        let bestI = 0, bestSum = a[0] + a[1];
        for (let i = 1; i < n - 1; i++) {
            const s = a[i] + a[i + 1];
            if (s < bestSum) { bestSum = s; bestI = i; }
        }
        const merged = a[bestI] + a[bestI + 1];
        a = a.slice(0, bestI).concat([merged], a.slice(bestI + 2));
        ops++;
    }
};
